// ============================ STANDING DECOR ============================
// softShadow -> body -> glow/rim accents -> outline(P.ink), anchor 'feet'

defineSprite('bdx_inferno_bonestack', 14, 14, (p) => {        // charred rib-stake half-buried in ash
  p.softShadow(7, 13, 6, 1.4, 0.42);
  for (let i = 0; i < 4; i++) {
    const x = 3 + i * 2, top = 6 + (i & 1);
    p.line(x, 12, x, top, darken(P.bone, 0.2));
    p.px(x, top, lighten(P.bone, 0.12));
  }
  p.line(3, 7, 9, 7, darken(P.bone, 0.15));
  p.ellipse(11, 10, 2.6, 2.2, darken(P.bone, 0.22));
  p.glow(11, 10, 1.6, P.ember, 0.4, 3);
  p.px(10, 10, P.emberL); p.px(12, 10, P.emberL);
  p.hline(1, 13, 12, IFL);
  p.speckle(2, 10, 11, 3, IFL, 4, 37);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineSprite('bdx_inferno_scoria', 18, 16, (p) => {           // volcanic breccia boulder cluster
  p.softShadow(9, 15, 8, 2, 0.44);
  p.ellipse(6, 11, 5, 4, IFA);
  p.ellipse(12, 12, 5, 3.6, IFB0);
  p.ellipse(9, 8, 4, 3.4, '#321c16');
  p.px(5, 8, lighten('#321c16', 0.15)); p.px(9, 6, lighten('#321c16', 0.18)); p.px(13, 9, lighten(IFB0, 0.14));
  p.line(7, 10, 9, 7, mix('#3a1c16', P.ember, 0.35));
  p.glow(8, 8, 2, P.ember, 0.3, 3);
  p.px(8, 8, P.emberL);
  p.speckle(3, 7, 13, 7, IFL, 6, 59);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineAnim('bdx_inferno_vent', 14, 10, 3, (p, f) => {         // steam/gas vent fissure (animated)
  p.softShadow(7, 9, 6, 1.4, 0.4);
  p.ellipse(7, 8, 6, 2, IFL);
  p.ellipse(7, 8, 4, 1.4, '#2a1410');
  p.line(3, 8, 5, 5, IFL); p.line(11, 8, 9, 5, IFL);
  p.glow(7, 7, 2.4, P.ember, 0.38 + f * 0.05, 3);
  p.px(7, 7, P.emberL);
  const s = [0, -1, -2][f];
  p.px(7, 5 + s, withAlpha(P.ember, 0.5));
  p.px(6, 3 + s, withAlpha('#4a2a22', 0.4));
  p.px(8, 2 + s, withAlpha('#3a1c16', 0.3));
  if (f === 1) p.sparkle(7, 4, P.emberL, 1);
  p.outline(P.ink);
}, { anchor: 'feet', fps: 4 });

defineSprite('bdx_inferno_snag', 16, 26, (p) => {             // charred dead-tree snag
  p.softShadow(8, 25, 7, 2, 0.42);
  p.rect(7, 14, 3, 11, IFL); p.rect(7, 14, 1, 11, '#2a1410');
  p.speckle(7, 15, 3, 9, '#0f0806', 4, 43);
  p.line(9, 14, 13, 9, IFL); p.line(8, 12, 4, 7, IFL); p.line(9, 10, 12, 5, '#2a1410');
  p.px(13, 9, darken('#2a1410', 0.1)); p.px(4, 7, darken('#2a1410', 0.1));
  p.glow(8, 18, 2, P.ember, 0.32, 3);
  p.px(8, 18, P.emberL);
  p.outline(P.ink);
}, { anchor: 'feet' });

defineSprite('bdx_inferno_slagspike', 12, 20, (p) => {        // twisted rebar/slag ruin spike
  p.softShadow(6, 19, 5, 1.6, 0.4);
  p.line(6, 19, 4, 10, P.iron); p.line(4, 10, 7, 5, darken(P.iron, 0.15)); p.line(7, 5, 5, 1, P.iron);
  p.px(6, 19, lighten(P.iron, 0.1));
  p.px(4, 10, mix(P.iron, '#2a1410', 0.4)); p.px(7, 5, mix(P.iron, '#2a1410', 0.3));
  p.glow(5, 2, 1.6, P.ember, 0.35, 3);
  p.px(5, 1, P.emberL);
  p.speckle(4, 12, 4, 6, darken(P.iron, 0.25), 4, 23);
  p.outline(P.ink);
}, { anchor: 'feet' });

